const express = require('express');
const cors = require('cors');
const { MongoClient, ServerApiVersion } = require('mongodb');
require('dotenv').config();

const app = express();
const PORT = 8081;

// MongoDB Connection String
// For local MongoDB: mongodb://localhost:27017
// For MongoDB Atlas: mongodb+srv://username:password@cluster.mongodb.net/dbname
const MONGODB_URI = process.env.MONGODB_URI || 'mongodb://localhost:27017';
const DB_NAME = 'professional_db';
const COLLECTION_NAME = 'professionals';

let mongoClient;
let database;

// Sample professional data for initialization
const sampleProfessionalData = {
  professionalName: "James Mburu Maina",
  base64Image: "data:image/jpeg;base64,",
  nameLink: {
    firstName: "James",
    url: "https://www.linkedin.com/in/james-mburu-maina-030018308"
  },
  primaryDescription: "Cloud Solutions Architect | ICT Infrastructure Specialist | Full-Stack Developer | Digital Health Innovator",
  workDescription1: "James Mburu Maina is an experienced ICT professional and Cloud Solutions Architect at Kenyatta National Hospital with over 7 years of experience in network infrastructure, systems administration, cloud technologies, and healthcare digital transformation. He specializes in enterprise IT support, hospital systems integration, cybersecurity, and scalable cloud solutions within high-demand healthcare environments.",
  workDescription2: "He is also the founder and developer of AfyaConnect, an AI-powered telemedicine and smart hospital management platform designed for African healthcare systems. James is currently pursuing a Bachelor of Applied Science in Software Development at BYU–Idaho while expanding his expertise in full-stack development, AI integration, and modern healthcare technologies.",
  linkTitleText: "Connect  Me",
  linkedInLink: {
    text: "LinkedIn",
    link: "https://www.linkedin.com/in/james-mburu-maina-030018308"
  },
  githubLink: {
    text: "GitHub",
    link: "https://github.com/jmburu7577"
  }
};

// Middleware
app.use(cors());
app.use(express.json());

// Connect to MongoDB
async function connectToMongoDB() {
  try {
    mongoClient = new MongoClient(MONGODB_URI, {
      serverApi: {
        version: ServerApiVersion.v1,
        strict: true,
        deprecationErrors: true,
      }
    });

    await mongoClient.connect();
    database = mongoClient.db(DB_NAME);
    
    console.log('Connected to MongoDB successfully!');
    
    // Initialize database with sample data if empty
    await initializeDatabaseIfEmpty();
  } catch (error) {
    console.error('Failed to connect to MongoDB:', error);
    console.log('Continuing without MongoDB connection...');
  }
}

// Initialize database with sample data if collection is empty
async function initializeDatabaseIfEmpty() {
  try {
    const collection = database.collection(COLLECTION_NAME);
    const count = await collection.countDocuments();
    
    if (count === 0) {
      const result = await collection.insertOne(sampleProfessionalData);
      console.log(`Sample data inserted with ID: ${result.insertedId}`);
    } else {
      console.log(`Collection already has ${count} document(s)`);
    }
  } catch (error) {
    console.error('Error initializing database:', error);
  }
}

// GET endpoint to fetch professional data from MongoDB
app.get('/professional', async (req, res) => {
  try {
    if (!database) {
      // Fallback to sample data if MongoDB is not connected
      return res.json(sampleProfessionalData);
    }

    const collection = database.collection(COLLECTION_NAME);
    const data = await collection.findOne({});
    
    if (data) {
      // Remove MongoDB _id from response if desired
      const { _id, ...professionalData } = data;
      res.json(professionalData);
    } else {
      res.json(sampleProfessionalData);
    }
  } catch (error) {
    console.error('Error fetching professional data:', error);
    res.status(500).json({ error: 'Failed to fetch professional data' });
  }
});

// Root endpoint
app.get('/', (req, res) => {
  res.json({ 
    message: 'Professional Profile API is running! Use /professional for data' });
});

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'Backend server is running' });
});

// Start server
async function startServer() {
  await connectToMongoDB();
  
  app.listen(PORT, () => {
    console.log(`Server is running on http://localhost:${PORT}`);
    console.log(`Professional data endpoint: http://localhost:${PORT}/professional`);
  });
}

startServer();
